resumo_json:
{
  "resumo": {
    "titulo": "Acompanhamento PMC com Mentor Issao Yokoi - Avatares IA e Planejamento de Marketing",
    "topicos": [
      {
        "tema": "Ferramentas de IA para Criação de Avatares",
        "pontos": [
          "Ferramentas gratuitas não oferecem controle de movimento, essencial para replicar sinalização em Libras",
          "Higsfield foi indicado como a plataforma mais completa para avatares falantes e vídeos instrucionais com controle de movimento",
          "Cling Motion é outra IA para controle de movimento de vídeo, integrada ao Higsfield",
          "Regen cria avatares mais estáticos (locutor parado), com custo similar ao Higsfield"
        ]
      },
      {
        "tema": "Fluxo de Trabalho para Geração de Imagens de Alta Qualidade",
        "pontos": [
          "Passo 1: gerar imagem base no Google Banana Pro (gratuito, mas com marca d'água)",
          "Passo 2: realizar upscale para aumentar qualidade e adicionar detalhes realistas (pele, cabelo)",
          "Passo 3: animação via plataforma paga",
          "Ferramentas de upscale indicadas: Lupa AI e Magnific"
        ]
      },
      {
        "tema": "Comparativo de Plataformas Pagas e Custo-Benefício",
        "pontos": [
          "Plano Ultimate do Rigsfield oferece geração de imagem ilimitada e Cling Motion Control com limite de créditos",
          "Freepik foi recomendado como melhor custo-benefício: plano premium inclui créditos para ~3.600 imagens e 120 vídeos, além de acesso à ferramenta Magnific",
          "Todas as plataformas que permitem avatares com movimento são pagas"
        ]
      },
      {
        "tema": "Técnicas de Prompt e Imagem de Referência",
        "pontos": [
          "Usar prompt fotográfico profissional (pode ser gerado por chatbot) para refinar estilo",
          "Colocar foto de referência antes do prompt para que a IA crie no estilo desejado",
          "Demonstração prática de upload de imagem de referência no Freepik com prompt 'mulher executiva, pose de empoderamento'",
          "Possibilidade de remover fundo para criação de banners"
        ]
      },
      {
        "tema": "Planejamento de Marketing com IA Manos",
        "pontos": [
          "Dayane buscava adaptar planejamento semestral/anual para sua empresa de treinamento em Libras",
          "Issao demonstrou uso do Manos para gerar planejamento anual completo com análise de risco, plano 5W2H, projeção de ROI e análise de gaps e oportunidades",
          "Ao incluir Campo Grande, MS, o Manos considerou a realidade regional, pesquisando dados demográficos e legislações locais sobre inclusão e demanda por Libras",
          "Manos diferencia-se do GPT por gerar protocolos e documentos via múltiplos agentes integrados; foi adquirido pela Meta"
        ]
      },
      {
        "tema": "Resultados do Plano de Marketing Gerado",
        "pontos": [
          "Projeção de investimento de R$ 97.200 e receita projetada de R$ 187.000 no primeiro ano",
          "Meta de ROI de 1.000% no primeiro ano",
          "Plano inclui ações detalhadas semana a semana no Instagram para janeiro, fevereiro e março",
          "Estrutura baseada no método 5W2H para clareza e eficiência na execução"
        ]
      }
    ]
  }
}

{
  "resumo": {
    "titulo": "Acompanhamento com Mentor - Rodrigo Nogueira e Paulo Berlfein (Ortopedista)",
    "topicos": [
      {
        "tema": "Contexto e Desafio com Convênios",
        "pontos": [
          "Paulo Berlfein é médico ortopedista com agenda preenchida por boca a boca, sem presença digital prévia",
          "A maioria dos pacientes paga convênio, gerando baixo lucro e pouca margem",
          "Pacientes de alto poder aquisitivo preferem viajar para São Paulo para procedimentos particulares",
          "Estratégia central: agregar serviços não cobertos pelo convênio para aumentar o ticket médio"
        ]
      },
      {
        "tema": "Estrutura de Pacotes Complementares",
        "pontos": [
          "Três pacotes principais complementares à cirurgia coberta pelo convênio: reabilitação individualizada, analgesia e medicina regenerativa",
          "Reabilitação individualizada (fisioterapia): R$ 3.000 a R$ 3.500",
          "Analgesia (redução da dor pós-cirúrgica): média de R$ 3.500",
          "Medicina regenerativa (célula-tronco): R$ 8.000 a R$ 18.000",
          "Pacote pré-operatório foi despriorizados por não alterar significativamente o resultado cirúrgico"
        ]
      },
      {
        "tema": "Processo de Vendas e Barreiras Culturais",
        "pontos": [
          "Paulo apresenta os pacotes ao paciente após explicar a cirurgia, na ordem: analgesia, reabilitação, regenerativa",
          "Barreira cultural em Campo Grande: pacientes resistem a pagar além do convênio",
          "Rodrigo sugeriu abordagem de downsell caso o paciente recuse o pacote completo"
        ]
      },
      {
        "tema": "Estratégia de Combos e Ancoragem de Preço",
        "pontos": [
          "Criação do 'Pacote Reabilitação 360', unindo reabilitação com analgesia",
          "Ancoragem: valor separado seria R$ 8.000; combo com desconto especial de R$ 7.000 (10x de R$ 700) se fechado na hora",
          "Dificuldade de acesso como gatilho: paciente que não fechar entra em fila de espera, criando senso de urgência"
        ]
      },
      {
        "tema": "Posicionamento e Técnicas de Vendas",
        "pontos": [
          "Paulo quer manter imagem de médico que busca o melhor para o paciente, não de vendedor",
          "Rodrigo propôs adaptar as técnicas para preservar a integridade profissional de Paulo",
          "Uso de IA para explicar procedimentos complexos (ex: célula-tronco) aumentou credibilidade junto aos pacientes"
        ]
      },
      {
        "tema": "Recursos Visuais e Apresentação no Consultório",
        "pontos": [
          "Sugestão de usar TV na sala de espera com apresentação de slides dos pacotes",
          "Estrutura da apresentação: o que é, para quem é, para quem não é, benefícios e problemas resolvidos",
          "Flyers com QR Code para o paciente consultar em casa também foram considerados",
          "Paulo tem site feito no Labove como base de conteúdo"
        ]
      },
      {
        "tema": "Janela de Decisão e Processo do Convênio",
        "pontos": [
          "Autorização do convênio leva cerca de 21 dias úteis, criando uma janela para o paciente decidir sobre upgrade",
          "Assistente de Paulo lembra o paciente sobre os pacotes, mas não realiza a apresentação",
          "Rodrigo sugeriu ser intencional na oferta de reabilitação em cada consulta de acompanhamento pós-operatório"
        ]
      },
      {
        "tema": "Recorrência e Infiltrações",
        "pontos": [
          "Infiltrações têm duração de cerca de 1 ano e podem ser combinadas com analgesia ou célula-tronco",
          "Reabilitação pós-cirúrgica (4 meses) pode ser posicionada como uma 'academia na clínica'",
          "Pacientes acompanhados mensalmente por 4 a 6 meses após a cirurgia são oportunidade para oferta de upgrade"
        ]
      },
      {
        "tema": "Marketing e Contratação de Profissional",
        "pontos": [
          "Paulo planeja contratar profissional recém-formado em marketing para gestão de redes sociais (3 posts por semana)",
          "Rodrigo recomendou perfil analítico e dominante, sem vícios de mercado, para ser treinado dentro do programa",
          "Execução de marketing pode ser facilitada por IA"
        ]
      },
      {
        "tema": "Próximos Passos",
        "pontos": [
          "Rodrigo enviará estrutura de apresentação para rascunho dos pacotes (a ser feita no Manus ou similar)",
          "Paulo enviará detalhes dos pacotes para apoiar a estruturação do material",
          "Rodrigo sugeriu implementação de CRM (disponível no programa Galdino) para gerenciar contatos e medir conversão"
        ]
      }
    ]
  }
}

{
  "resumo": {
    "titulo": "Acompanhamento com Mentor - Geração de Avatar com IA (Dayane Telles e Issao Yokoi)",
    "topicos": [
      {
        "tema": "Acesso e materiais da reunião",
        "pontos": [
          "Dayane entrou pelo celular devido a problema no computador",
          "Fernanda enviou fotos e vídeos para Issao usar como referência",
          "Dayane não contratou o serviço no FPIC por limitações financeiras, mas planeja fazê-lo no próximo mês"
        ]
      },
      {
        "tema": "Geração de avatar com IA (ChatGPT, Gemini e Whisk)",
        "pontos": [
          "Issao demonstrou o uso do ChatGPT para gerar prompts detalhados e do Gemini para criar as imagens",
          "O processo consiste em descrever a imagem original no GPT para gerar um prompt que mantenha os traços físicos no Gemini",
          "Whisk foi usado para testar diferentes estilos, fundos e geração de fotos de corpo inteiro"
        ]
      },
      {
        "tema": "Dificuldades de semelhança e ajustes no avatar",
        "pontos": [
          "Dayane identificou detalhes indesejados no avatar: boca diferente, anel e brinco que ela não usa",
          "Issao ajustou os prompts para remover acessórios e alterar ângulos da imagem",
          "Issao atribuiu parte da insatisfação ao perfeccionismo de Dayane e sugeriu fazer uma enquete para obter feedback externo"
        ]
      },
      {
        "tema": "Processo iterativo e colaboração remota",
        "pontos": [
          "Ambos concordaram que a geração de imagens exige tentativa e erro com ajustes contínuos nos prompts",
          "Usaram o AnyDesk para Issao acessar o computador de Dayane e salvar os resultados na conta dela",
          "Issao recomendou que Dayane faça as gerações na própria conta para evitar múltiplos avatares na conta dele"
        ]
      },
      {
        "tema": "Ferramentas de design e aprendizado para o site",
        "pontos": [
          "Issao mencionou Canva e Lovart como ferramentas de criação de arte e design",
          "Dayane deseja aprender a inserir a foto no site por conta própria",
          "Foi discutida a possibilidade de fazer upload da foto e remover o fundo diretamente no site"
        ]
      },
      {
        "tema": "Pagamento das aulas",
        "pontos": [
          "Dayane informou dificuldade em fazer o investimento imediatamente por compromissos financeiros",
          "Planeja realizar o pagamento de forma mensal, começando no final do mês"
        ]
      }
    ]
  }
}

{
  "resumo": {
    "titulo": "Acompanhamento PMC - Ambia Agro: Automação de Propostas com IA",
    "topicos": [
      {
        "tema": "Apresentação das partes e contexto",
        "pontos": [
          "Rafael Martins representa a Ambia Agro, consultoria agroambiental em Cuiabá-MT especializada em regularização ambiental, certificações e consultoria jurídica para agronegócio",
          "Issao Yokoi é arquiteto especializado em 3D e IA, baseado em São Paulo",
          "A empresa está implementando o Black CRM e enfrenta gargalos em processos comerciais e operacionais"
        ]
      },
      {
        "tema": "Desafio principal: elaboração manual de propostas",
        "pontos": [
          "O processo atual é manual, complexo e demorado, baseado em modelos antigos do Word",
          "Requer conhecimento técnico aprofundado devido à natureza consultiva e de 'cauda longa' das vendas",
          "A prioridade da empresa é automatizar a geração de propostas, contratos e peças de projeto com IA"
        ]
      },
      {
        "tema": "Ferramentas e integrações consideradas",
        "pontos": [
          "Manos foi sugerido por Islan como plataforma de proposta por integrar-se ao Black CRM",
          "Issao Yokoi sugeriu workflow com Notebook LM para coleta de informações, seguido de Gemini e Manos para geração dos documentos",
          "Rafael tem familiaridade com N8N e experiência em gestão de projetos, mas sem implementação completa de IA até o momento"
        ]
      },
      {
        "tema": "Planilha de precificação e complexidade dos orçamentos",
        "pontos": [
          "A planilha cobre categorias de trabalho, custos, impostos e margem de lucro, sendo a base dos orçamentos",
          "Os orçamentos não são engessados e variam conforme o serviço, área, número de matrículas e outros fatores",
          "Rafael ajusta os valores para garantir margem de lucro entre 15% e 30%",
          "Serviços como estudo de tipologia podem levar de um a um ano e meio para conclusão"
        ]
      },
      {
        "tema": "Estrutura desejada para o sistema de propostas",
        "pontos": [
          "Plataforma modular onde cada serviço é um módulo independente",
          "Sistema CRUD para cadastrar serviços, categorias e valores com campos personalizáveis",
          "Serviços divididos em fixos (ex: outorga de irrigação) e variáveis (ex: CAR, PEF, Georreferenciamento)",
          "Um único serviço como CAR pode desdobrar-se em micro-serviços ou sub-serviços incluídos na mesma proposta ou separados por etapas",
          "Uso de Termos de Referência de órgãos ambientais para gerar escopos e textos automaticamente"
        ]
      },
      {
        "tema": "Fluxo de geração de propostas",
        "pontos": [
          "Dados cadastrais virão do CRM para a plataforma de proposta",
          "O sistema puxará automaticamente textos descritivos dos serviços cadastrados, eliminando cópia manual",
          "A plataforma gerará uma pré-proposta, possivelmente via agente de IA",
          "A proposta gerada será enviada de volta ao CRM para automações como envio por e-mail ou WhatsApp"
        ]
      },
      {
        "tema": "Próximos passos acordados",
        "pontos": [
          "Rafael fornecerá a Issao: a planilha de precificação e de 5 a 10 modelos de propostas (priorizando PEF, tipologia, georreferenciamento e CAR)",
          "Issao desenvolverá um MVP de sistema modular baseado na planilha e nos Termos de Referência",
          "Reunião de acompanhamento agendada para o dia 19 (segunda-feira) para apresentação do protótipo, após evento de feira de Rafael"
        ]
      }
    ]
  }
}

{
  "resumo": {
    "titulo": "Acompanhamento com Mentor - Rodrigo Nogueira e Manuela Binhotti",
    "topicos": [
      {
        "tema": "Personalização do Produto e Provador Virtual",
        "pontos": [
          "Ideia de implementar um 'provador virtual' no site onde clientes fazem upload de foto e se veem usando o jaleco",
          "Ferramentas sugeridas: 'Nano Banana' (Google) e 'Lovable'",
          "Inclusão de marca d'água nas fotos para evitar uso indevido",
          "Frase estratégica sugerida: 'materializa seu sonho'"
        ]
      },
      {
        "tema": "Captação de Leads com o Provador Virtual",
        "pontos": [
          "Provador virtual como ferramenta de geração de leads",
          "Fluxo: cliente faz o teste e ao final recebe link para compra"
        ]
      },
      {
        "tema": "Campanha de 10 Anos da Marca",
        "pontos": [
          "Foco em gerar 'burburinho' prévio para captação de leads",
          "Uso de grupos de WhatsApp para liberar ofertas exclusivas antes do público geral",
          "Marca possui quase 80.000 clientes — tráfego orgânico mais eficaz que pago",
          "Etapas: burburinho, captação (save the date) e vendas",
          "Aniversário previsto para cerca do dia 20 de março"
        ]
      },
      {
        "tema": "Cronograma da Campanha",
        "pontos": [
          "Campanha de volta às aulas na semana seguinte, estendendo-se até março",
          "Ponto alto de vendas: semana de 19 a 26 de fevereiro",
          "Preparação dos 10 anos iniciando em 22 de fevereiro para vendas ao longo de março",
          "Atenção aos feriados e Copa do Mundo em fevereiro"
        ]
      },
      {
        "tema": "Estratégia de Produtos e Ofertas",
        "pontos": [
          "Descartada coleção exclusiva de 10 anos para não datar os produtos (marca trabalha com itens atemporais)",
          "Oferta no estilo Black Friday considerada mais apropriada",
          "Última semana de fevereiro para antecipação; vendas iniciando em março"
        ]
      },
      {
        "tema": "Eventos e Experiência do Cliente",
        "pontos": [
          "Evento na loja no dia 20 de março para comemoração",
          "Item colecionável ou algo diferente nas lojas durante a campanha",
          "Quatro depoimentos/vídeos de clientes — um por semana em março como background para ofertas",
          "Entrevistas focadas nos valores e cultura da empresa"
        ]
      },
      {
        "tema": "Estratégia de Promoções e Calendário",
        "pontos": [
          "Sem liquidação em março (mês de boas vendas)",
          "Liquidação reservada para abril ou junho (meses mais fracos)",
          "Dia da Mulher (8 de março) usado para ações de branding",
          "Discussão sobre desconto progressivo versus produtos limitados para gerar escassez"
        ]
      },
      {
        "tema": "Crescimento de Seguidores e Engajamento",
        "pontos": [
          "Incentivo a clientes para postarem fotos com os produtos ('você faz parte dessa história')",
          "Meta de alcançar 100.000 seguidores até o final do ano",
          "Anúncios de visita ao perfil no Instagram indicados como método de menor custo para ganhar seguidores"
        ]
      },
      {
        "tema": "Estratégia B2B e Programa de Indicação",
        "pontos": [
          "Reunião futura planejada com foco em B2B (evento de odontologia, revenda e instituições de ensino)",
          "Programa de indicação: ligar para clientes fidelizados para levantar hipóteses de recompensa",
          "Abordagem de agradecimento e consulta sobre melhor forma de recompensar indicações",
          "Manuela realizará pesquisa com clientes sobre o programa"
        ]
      },
      {
        "tema": "Tópicos Pendentes e Próximas Etapas",
        "pontos": [
          "Caixa de assinatura: Rodrigo enviará link da landing page para análise de copyright",
          "Campanha de volta às aulas com quatro oportunidades: faculdade, ensino médio, instituições e professores",
          "Reestruturação do plano de revenda e padronização para clínicas",
          "Manuela enviará plano de revenda para Rodrigo analisar",
          "Rodrigo enviará perguntas para estudos de caso e roteiro de indicação",
          "Reunião na próxima semana para discutir B2B"
        ]
      }
    ]
  }
}

{
  "resumo": {
    "titulo": "Acompanhamento com Mentor - Issao Yokoi e Manuela Santos",
    "topicos": [
      {
        "tema": "Projeto de Aniversário de 10 Anos e Hiperpersonalização",
        "pontos": [
          "Manuela deseja criar uma experiência 'uau' para os 10 anos da marca com hiperpersonalização",
          "Ideia central: usar IA para que clientes se vejam vestindo o jaleco no site com simulação de bordado"
        ]
      },
      {
        "tema": "Avatar 360° e Simulação de Jaleco no Site",
        "pontos": [
          "Issao sugeriu avatar gerado a partir de fotos de frente e lado do cliente, com aplicação simplificada do logo",
          "A solução será integrada diretamente ao site, não em landing page separada",
          "Issao se ofereceu para montar o processo e depois ensinar Manuela a utilizá-lo"
        ]
      },
      {
        "tema": "Materiais Necessários para Desenvolvimento do Avatar",
        "pontos": [
          "Fotos dos jalecos em alta resolução (frente e verso)",
          "Fotos de modelos plus size (até G3)",
          "Exemplos de logo bordado"
        ]
      },
      {
        "tema": "Automação no Instagram",
        "pontos": [
          "Manuela identificou necessidade de automação no Instagram além do WhatsApp",
          "Objetivo é lidar com grande fluxo de clientes sem parecer robô",
          "Issao ficou de pesquisar ferramentas adequadas para automação orgânica"
        ]
      },
      {
        "tema": "Landing Page e Experiência do Jaleco Box",
        "pontos": [
          "A landing page atual do Jaleco Box (caixa de assinatura) é considerada fraca e terceirizada",
          "Manuela quer criar a própria landing page para ter mais controle, reduzir custos e melhorar a estética",
          "Issao sugeriu avatar animado abrindo a caixa para gerar desejo e gatilho de compra",
          "Desafio principal é fidelizar clientes dado que o produto tem alta durabilidade",
          "Avaliar ajuste de precificação para plano de 12 meses e adição de brindes/acessórios"
        ]
      },
      {
        "tema": "Sistema de Gestão Interna com IA (Manus)",
        "pontos": [
          "Manuela está desenvolvendo um sistema no Manus para centralizar dados de todas as áreas da empresa",
          "O sistema inclui módulos comercial, marketing, financeiro e estoque com alertas preditivos",
          "Já foi criado um agente para cálculo e recomendação de frete, com limitações por falta de contrato com transportadoras",
          "Objetivo final: relatórios integrados e alertas como variação do dólar para compra de matéria-prima"
        ]
      },
      {
        "tema": "Próximos Passos",
        "pontos": [
          "Manuela enviará fotos dos jalecos, modelo plus size e logo bordado para Issao via Giovana",
          "Issao pesquisará ferramentas de automação para Instagram",
          "Manuela continuará desenvolvendo o sistema no Manus e marcará nova sessão com Issao para trocar ideias"
        ]
      }
    ]
  }
}

{
  "resumo": {
    "titulo": "Acompanhamento com Mentor - Railson Alves (Bonvie Wear)",
    "topicos": [
      {
        "tema": "Contexto e Desafios Atuais da Bonvie Wear",
        "pontos": [
          "Loja com 35 anos mudou para endereço maior há um ano, mas o fluxo de clientes diminuiu",
          "Período de luto interrompeu a produção de conteúdo, causando queda de 30% nas vendas de dezembro",
          "Sem agência de marketing após experiências anteriores fracassadas",
          "Sensação de estar 'nadando contra a maré' apesar dos esforços"
        ]
      },
      {
        "tema": "Objetivos e Metas",
        "pontos": [
          "Meta de faturamento de R$ 500.000 por mês",
          "Visão de escalar vendas e abrir lojas em outros locais",
          "Público-alvo classe B/A",
          "Plano de 4 encontros: diagnóstico, linha editorial, arquétipos e implementação"
        ]
      },
      {
        "tema": "Estratégia de Funis de Marketing",
        "pontos": [
          "Necessidade urgente de funis de atração (topo), conexão (meio) e vendas (fundo)",
          "Dependência atual apenas do frágil funil orgânico",
          "Indicação do especialista Jeff para tráfego pago de atração e conversão",
          "Tráfego pago no Google recomendado mesmo para município pequeno (19.000 habitantes)"
        ]
      },
      {
        "tema": "Posicionamento e Produção de Conteúdo",
        "pontos": [
          "Criar posicionamento único e sólido sem depender de conteúdo viral",
          "Foco em atrair cliente de alto valor, não em métricas de vaidade (curtidas e comentários)",
          "Rafaela deve atuar como influenciadora e CEO da marca, com conteúdo autêntico",
          "Conteúdo deve focar na história da marca e no produto, não em tendências virais"
        ]
      },
      {
        "tema": "Posicionamento como Curadoria de Multimarcas",
        "pontos": [
          "Bonvie Wear deve se posicionar como loja de multimarcas que faz curadoria",
          "Criação de coleções temáticas sazonais (verão, Dia das Mães) com base nas marcas disponíveis",
          "80% das vendas já ocorrem via 'bags' personalizadas (mala em casa) — experiência a ser divulgada",
          "Transição gradual para marca própria como caminho para aumentar margem de lucro"
        ]
      },
